using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        MimeType = "text/plain"),
     Description("Returns the current application version.")]
    public static string GetVersion() => "1.0.0";
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the provided message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Reverses the provided text.")]
    public static string ReverseText(
        [Description("The text to reverse")] string text)
    {
        var chars = text.ToCharArray();
        Array.Reverse(chars);
        return new string(chars);
    }
}

